mapper.select:
SELECT * FROM esg.tb_audit_execution_plan
WHERE comp_id = #{compId}
AND write_year = #{writeYear}
ORDER BY use_yn DESC, write_dt DESC, doc_no DESC

SELECT taed.*,
toi.orgn_nm FROM esg.tb_audit_execution_plan_detail taed
LEFT JOIN esg.tb_orgn_info toi on toi.orgn_id = taed.orgn_id
WHERE write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
ORDER BY taed.use_yn DESC,
 taed.created_at DESC

SELECT tarr.*,toi.orgn_nm

 FROM esg.tb_audit_execution_plan_detail tarr
LEFT JOIN esg.tb_orgn_info toi on toi.orgn_id = tarr.orgn_id
WHERE tarr.write_year = #{writeYear}
  AND tarr.doc_no = #{docNo}
  AND tarr.doc_type = #{docType}
  AND tarr.doc_seq = #{docSeq}

SELECT taeh.*, thi.hr_nm FROM esg.tb_audit_execution_plan_detail_hr taeh
LEFT JOIN esg.tb_hr_info thi on thi.hr_id = taeh.hr_id
WHERE taeh.write_year = #{writeYear}
  AND taeh.doc_no = #{docNo}
  AND taeh.doc_type = #{docType}
  AND taeh.doc_seq = #{docSeq}

SELECT tarr.* FROM esg.tb_audit_result_report_detail tarr
WHERE tarr.write_year = #{writeYear}
  AND tarr.doc_no = #{docNo}
  AND tarr.doc_type = #{docType}
  AND tarr.doc_seq = #{docSeq}
ORDER BY tarr.use_yn DESC, tarr.created_at DESC, tarr.doc_seq_detail asc

SELECT taeh.*, thi.hr_nm FROM esg.tb_audit_result_report_hr taeh
LEFT JOIN esg.tb_hr_info thi on thi.hr_id = taeh.hr_id
WHERE taeh.write_year = #{writeYear}
  AND taeh.doc_no = #{docNo}
  AND taeh.doc_type = #{docType}
  AND taeh.doc_seq = #{docSeq}

mapper.update:
DELETE FROM esg.tb_audit_result_report
WHERE  write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}

UPDATE esg.tb_audit_result_report
SET audit_dt=#{auditDt},
audit_st_time=#{auditStTime},
audit_ed_time=#{auditEdTime},
orgn_id=#{orgnId},
remark=#{remark},
use_yn=#{useYn},
updated_at=now(),
updated_by=#{updatedBy}
WHERE  write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}

UPDATE esg.tb_audit_result_report_detail SET
target_job=#{targetJob},
result=#{result},
remark=#{remark},
use_yn=#{useYn},
updated_at=now(),
updated_by=#{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
  AND doc_seq = #{docSeq}
  AND doc_seq_detail = #{docSeqDetail}

mapper.delete:
DELETE FROM esg.tb_audit_result_report_hr
    WHERE write_year = #{writeYear}
      AND doc_no = #{docNo}
      AND doc_type = #{docType}
      AND doc_seq = #{docSeq}
